from flask import Flask, send_from_directory
import os

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}

def allowed_file(filename):
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/uploads/<path:filename>')
def uploaded_file(filename):
    # Resolve the path to ensure it's within the uploads directory
    safe_path = os.path.join(UPLOAD_FOLDER, filename)
    
    # Check if the resolved path starts with the UPLOAD_FOLDER
    if not safe_path.startswith(os.path.abspath(UPLOAD_FOLDER)):
        return "Invalid file path", 403
    
    # Ensure the file exists and is allowed
    if not os.path.isfile(safe_path) or not allowed_file(filename):
        return "File not found or invalid type", 404
    
    return send_from_directory(UPLOAD_FOLDER, filename)

if __name__ == '__main__':
    app.run(debug=True)